parameters.jsCode:
// Pega os dados principais da atualização
const executionData = $input.item.json.body.data.rows[0];
const context = executionData.context;
const payload = context.raw_payload;

// Organiza apenas o que importa para a automação
return {
  info: {
    id_execucao: executionData.id,
    checkout_id: executionData.checkout_id,
    flow_code: executionData.flow_code,
    status_atual: executionData.status,
  },
  cliente: {
    nome: context.full_name,
    primeiro_nome: context.first_name,
    email: context.email,
    whatsapp: context.phone,
    documento: context.doc_number
  },
  pagamento: {
    metodo: context.payment_method,
    valor_total: context.valor_total,
    pix_copia_cola: context.pix_code,
    pix_vencimento: payload.resource.pix.data.pix_expiration_date
  },
  produto: {
    nome: payload.resource.items.data[0].sku.data.title,
    sku: payload.resource.items.data[0].item_sku,
    link_venda: payload.resource.items.data[0].sku.data.purchase_url
  },
  entrega: {
    endereco_completo: context.address,
    cidade: payload.resource.shipping_address.data.city,
    estado: payload.resource.shipping_address.data.state
  }
};

parameters.query:
/* 1. Se for PAUSED, marca o step atual como SKIPPED para "limpar" a fila */
UPDATE flow_step_executions
SET status = 'skipped'
WHERE flow_execution_id = $1::uuid 
  AND status = 'scheduled'
  AND $2 = 'paused';

/* 2. Se for CANCELLED, marca como CANCELLED mesmo */
UPDATE flow_step_executions
SET status = 'cancelled'
WHERE flow_execution_id = $1::uuid 
  AND status = 'scheduled'
  AND $2 = 'cancelled';

/* 3. Atualiza a execução principal */
UPDATE flow_executions
SET status = $2,
    cancelled_at = CASE WHEN $2 = 'cancelled' THEN NOW() ELSE cancelled_at END
WHERE id = $1::uuid;

/* 4. Retorna os IDs para deletar no Scheduler externo */
SELECT id as step_id, schedule_id FROM flow_step_executions
WHERE flow_execution_id = $1::uuid AND status IN ('skipped', 'cancelled');

