UPDATE flow_step_executions
SET status = $2 
WHERE flow_execution_id = $1::uuid 
  AND status = 'scheduled';

/* 2. Atualiza a execução principal (Removido updated_at) */
UPDATE flow_executions
SET 
  status = $2, 
  cancelled_at = CASE WHEN $2 = 'cancelled' THEN NOW() ELSE cancelled_at END
WHERE id = $1::uuid;

/* 3. Retorna os dados para o n8n deletar no Scheduler Externo */
SELECT 
  id as step_id,
  schedule_id,
  status
FROM flow_step_executions
WHERE flow_execution_id = $1::uuid
  AND status = $2;

